external_knowledge:
- The "industry classification" refers to a broad category under which a security falls, such as "2/3 Wheelers" or "Technology";
- "Ranked from highest to lowest" refers to the ordering of average daily trade values in descending order;
- "Organized by industry classification" implies grouping the results by the industry name.

sql:
SELECT security_id, AVG(close_price) AS average_close_price
FROM security_prices
GROUP BY security_id;

SELECT date, MAX(market_cap)
FROM security_prices
WHERE security_id = 1;

SELECT close_price
FROM security_prices
WHERE security_id = 0 AND date = '0';

SELECT feed_type, COUNT(*) as feed_count
FROM market_data_feeds
GROUP BY feed_type;

SELECT quantity
FROM security_trades
WHERE security_id = 1 AND trade_type = '1';

SELECT SUM(trade_value) AS total_trade_value
FROM security_trades
WHERE security_id = 0 AND date = '0';

SELECT SUM(quantity) AS total_volume
FROM security_trades
WHERE security_id = 0;
